// ---- helpers (unexported) --------------------------------------------

func pickRoot(p FolderTreeProps, kr folders.KindRoot) (FolderRoot, bool) {
	for _, r := range p.Roots {
		if r.KindRoot == string(kr) {
			return r, true
		}
	}
	return FolderRoot{}, false
}

func folderParentMatches(have *int64, want *int64) bool {
	if have == nil && want == nil {
		return true
	}
	if have == nil || want == nil {
		return false
	}
	return *have == *want
}

func folderParentAttr(p *int64) string {
	if p == nil {
		return ""
	}
	return fmt.Sprintf("%d", *p)
}

func hasChildren(all []folders.Folder, id int64) bool {
	for _, f := range all {
		if f.ParentID != nil && *f.ParentID == id {
			return true
		}
	}
	return false
}

func folderIndentStyle(depth int) string {
	if depth == 0 {
		return ""
	}
	return fmt.Sprintf("padding-left: %dpx;", depth*12)
}

func folderRowClass(p FolderTreeProps, f folders.Folder) string {
	cls := "bx-folder-rail__item"
	if p.FocusedID == f.ID {
		cls += " bx-folder-rail__item--focus"
	}
	if p.SelectedFolderID != nil && *p.SelectedFolderID == f.ID {
		cls += " bx-folder-rail__item--selected"
	}
	return cls
}

func folderSelectedAttr(p FolderTreeProps, f folders.Folder) string {
	if p.SelectedFolderID != nil && *p.SelectedFolderID == f.ID {
		return "true"
	}
	return "false"
}

func folderHref(f folders.Folder) templ.SafeURL {
	return templ.URL(fmt.Sprintf("/design/assets?folder_id=%d", f.ID))
}

func kindRootHref(kr string) templ.SafeURL {
	return templ.URL("/design/assets?kind=" + kr)
}

func dotForKind(kr string) string {
	switch kr {
	case "sprite":
		return "asset"
	case "tile":
		return "map"
	case "audio":
		return "audio"
	case "ui_panel":
		return "ui"
	}
	return "asset"
}

func folderContentsIDAttr(id *int64) string {
	if id == nil {
		return ""
	}
	return fmt.Sprintf("%d", *id)
}

func folderHeaderLabel(p FolderContentsProps) string {
	if p.FolderID != nil {
		return fmt.Sprintf("folder #%d", *p.FolderID)
	}
	switch p.Kind {
	case "sprite":
		return "Sprites (root)"
	case "tile":
		return "Tiles (root)"
	case "audio":
		return "Audio (root)"
	case "ui_panel":
		return "UI (root)"
	}
	return p.Kind
}

func folderContentsIncludes(p FolderContentsProps) string {
	// Closest section is the wrapper; HTMX will pick up the hidden
	// inputs + the changed select itself.
	return "closest section"
}

func availableSortModesForContents(p FolderContentsProps) []folders.SortMode {
	// Use the kind-aware sort list. Default to all if we can't resolve
	// the kind (shouldn't happen in practice — handler always sets it).
	kr := folders.KindRoot(p.Kind)
	if !kr.Valid() {
		// Fallback: image-style, no length.
		return []folders.SortMode{folders.SortAlpha, folders.SortDate, folders.SortType, folders.SortColor}
	}
	return folders.AvailableSortModes(kr)
}

func humanSortLabel(m folders.SortMode) string {
	switch m {
	case folders.SortAlpha:
		return "A → Z"
	case folders.SortDate:
		return "Newest first"
	case folders.SortType:
		return "By type"
	case folders.SortColor:
		return "By color"
	case folders.SortLength:
		return "By length"
	}
	return string(m)
}

